previewCss:
.darma-loader-uiverse-bubble-dots {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 4px;
      min-width: 70px;
      min-height: 20px;
    }
    .darma-loader-uiverse-bubble-dots i {
      display: block;
      width: 10px;
      height: 10px;
      border-radius: 50%;
      background: var(--loader-color, #14b8a6);
      animation: darma-loader-uiverse-bubble-dots-dotPulse 0.9s ease-in-out infinite;
    }
    .darma-loader-uiverse-bubble-dots i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-uiverse-bubble-dots i:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-uiverse-bubble-dots i:nth-child(3) { animation-delay: 0.24s; }
.darma-loader-uiverse-bubble-dots i:nth-child(4) { animation-delay: 0.36s; }
.darma-loader-uiverse-bubble-dots i:nth-child(5) { animation-delay: 0.48s; }
    @keyframes darma-loader-uiverse-bubble-dots-dotPulse { 0%, 100% { transform: translateY(0); opacity: .45; } 45% { transform: translateY(-12px); opacity: 1; } }

.darma-loader-confetti-dots {
  position: relative;
  display: inline-block;
  width: 70px;
  height: 54px;
  color: var(--loader-color, #6366f1);
}
.darma-loader-confetti-dots i {
  position: absolute;
  width: 10px;
  height: 10px;
  border-radius: 3px;
  background: currentColor;
  animation: darma-loader-confetti-dots-confetti 1s ease-in-out infinite;
}
.darma-loader-confetti-dots i:nth-child(1) { left: 4px; top: 34px; }
.darma-loader-confetti-dots i:nth-child(2) { left: 18px; top: 14px; animation-delay: .1s; }
.darma-loader-confetti-dots i:nth-child(3) { left: 34px; top: 30px; animation-delay: .2s; }
.darma-loader-confetti-dots i:nth-child(4) { left: 49px; top: 10px; animation-delay: .3s; }
.darma-loader-confetti-dots i:nth-child(5) { left: 60px; top: 36px; animation-delay: .4s; }
@keyframes darma-loader-confetti-dots-confetti {
  0%, 100% { transform: translateY(0) rotate(0deg); opacity: .35; }
  50% { transform: translateY(-12px) rotate(90deg); opacity: 1; }
}

.darma-loader-flip-square {
  display: inline-block;
  width: 48px;
  height: 48px;
  border-radius: 14px;
  background: var(--loader-color, #6366f1);
  animation: darma-loader-flip-square-flip 1.15s cubic-bezier(.7,.02,.26,.99) infinite;
}
@keyframes darma-loader-flip-square-flip {
  0% { transform: perspective(120px) rotateX(0) rotateY(0); }
  50% { transform: perspective(120px) rotateX(-180deg) rotateY(0); }
  100% { transform: perspective(120px) rotateX(-180deg) rotateY(-180deg); }
}

.darma-loader-uiverse-spectrum-bars {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 5px;
      height: 44px;
    }
    .darma-loader-uiverse-spectrum-bars i {
      display: block;
      width: 7px;
      height: 44px;
      border-radius: 999px;
      background: linear-gradient(180deg, var(--loader-color, #8b5cf6), var(--loader-secondary-color, #ddd6fe));
      transform-origin: center bottom;
      animation: darma-loader-uiverse-spectrum-bars-barPulse 0.8s ease-in-out infinite;
    }
    .darma-loader-uiverse-spectrum-bars i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-uiverse-spectrum-bars i:nth-child(2) { animation-delay: 0.09s; }
.darma-loader-uiverse-spectrum-bars i:nth-child(3) { animation-delay: 0.18s; }
.darma-loader-uiverse-spectrum-bars i:nth-child(4) { animation-delay: 0.27s; }
.darma-loader-uiverse-spectrum-bars i:nth-child(5) { animation-delay: 0.36s; }
    @keyframes darma-loader-uiverse-spectrum-bars-barPulse { 0%, 100% { opacity: .25; transform: scaleY(.5); } 45% { opacity: 1; transform: scaleY(1); } }
